hooks.onInit:
const s = world.state;
s.wSolNora = 6; s.wTiempoNora = 6; s.wFrioNora = 1.2;
s.wSolTeo = 1.2; s.wTiempoTeo = 1.2; s.wFrioTeo = 1.5;
s.wNoraDalia = 6; s.wTeoDalia = 1.2;
s.aRow1 = 0; s.aRow2 = 0;
s.backOn = 0; s.backT = 0;
s.accA = 0; s.accR = 0;
s.accCurve = [[0,50],[0.15,63],[0.3,74],[0.5,84],[0.7,90],[0.85,94],[1,96]];
for (const id of ['nora','teo','dalia','tobias']) { const e = world.byId(id); if (e) e._alpha = 0; }
const lu = world.byId('lucia'); if (lu) lu._alpha = 1;

hooks.onDraw:
const s = world.state;
const B = (id) => world.byId(id);
const nora = B('nora'), teo = B('teo'), dalia = B('dalia');
const UI = '"Plus Jakarta Sans", ui-sans-serif, system-ui, sans-serif';
const SRC = {
  sol:    { x: 175, y: 175, c: '#F4AC1D', label: 'sol' },
  tiempo: { x: 175, y: 300, c: '#5b8def', label: 'tiempo' },
  frio:   { x: 175, y: 425, c: '#22c4f8', label: 'frío' },
};
function cord(from, to, w, kind, a) {
  if (!from || !to || a <= 0.01 || w <= 0.05) return;
  ctx.save();
  ctx.lineCap = 'round';
  ctx.globalAlpha = Math.min(1, a) * 0.8;
  ctx.lineWidth = w;
  ctx.strokeStyle = kind === 'neg' ? '#3f6ea8' : '#c98a2e';
  ctx.beginPath(); ctx.moveTo(from.x, from.y); ctx.lineTo(to.x, to.y); ctx.stroke();
  if ((s.backOn || 0) > 0.5) {
    const p = s.backT || 0;
    const px = from.x + (to.x - from.x) * p, py = from.y + (to.y - from.y) * p;
    ctx.globalAlpha = Math.min(1, a);
    ctx.fillStyle = '#e0533e';
    ctx.beginPath(); ctx.arc(px, py, Math.max(4, w * 0.9), 0, Math.PI * 2); ctx.fill();
  }
  ctx.restore();
}
cord(SRC.sol, nora, s.wSolNora, 'pos', s.aRow1);
cord(SRC.tiempo, nora, s.wTiempoNora, 'pos', s.aRow1);
cord(SRC.frio, nora, s.wFrioNora, 'neg', s.aRow1);
cord(SRC.sol, teo, s.wSolTeo, 'pos', s.aRow1);
cord(SRC.tiempo, teo, s.wTiempoTeo, 'pos', s.aRow1);
cord(SRC.frio, teo, s.wFrioTeo, 'neg', s.aRow1);
cord(nora, dalia, s.wNoraDalia, 'pos', s.aRow2);
cord(teo, dalia, s.wTeoDalia, 'neg', s.aRow2);
const aS = s.aRow1 || 0;
if (aS > 0.01) {
  for (const k in SRC) {
    const p = SRC[k];
    ctx.save();
    ctx.globalAlpha = aS;
    ctx.beginPath(); ctx.arc(p.x, p.y, 21, 0, Math.PI * 2);
    ctx.fillStyle = '#141a34'; ctx.fill();
    ctx.lineWidth = 2.5; ctx.strokeStyle = p.c; ctx.stroke();
    ctx.fillStyle = '#FBFAF6'; ctx.font = '700 17px ' + UI;
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.fillText('1', p.x, p.y);
    ctx.fillStyle = p.c; ctx.font = '600 13px ' + UI; ctx.textBaseline = 'alphabetic';
    ctx.fillText(p.label, p.x, p.y - 30);
    ctx.restore();
  }
}
if ((s.accA || 0) > 0.01 && s.accCurve) {
  ctx.save();
  ctx.globalAlpha = s.accA;
  const f = world.draw.axes(648, 74, 250, 148, { xDomain: [0, 1], yDomain: [40, 100],
    xTicks: [], yTicks: [50, 75, 100], yFormat: function (v) { return v + '%'; },
    color: 'rgba(232,226,210,0.4)', labelColor: '#9aa3bd' });
  world.draw.plot(f, s.accCurve, { color: '#4f8a5e', width: 2.5, reveal: s.accR || 0 });
  ctx.fillStyle = '#9aa3bd'; ctx.font = '600 12px ' + UI;
  ctx.textAlign = 'left'; ctx.textBaseline = 'alphabetic';
  ctx.fillText('aciertos', 648, 62);
  ctx.restore();
}
for (const e of world.entities) { if (e.type === 'learner') world.draw.learner(e); }
